import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { getOrCreateOrg } from "@/lib/get-auth-org";
import { prisma } from "@atlas/db";
import { z } from "zod";

const AlertPrefUpdateSchema = z.object({
  mode: z.enum(["immediate", "off"]),
  severityFloor: z.enum(["warning", "critical"]),
  slackWebhookUrl: z.string().url().optional().or(z.literal("")),
  agentId: z.string().optional(),
  customEvalCriteria: z.string().max(1000).optional(),
});

export async function GET(req: NextRequest) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const { orgId } = await getOrCreateOrg(user);

  const agentId = req.nextUrl.searchParams.get("agentId") ?? null;

  if (agentId) {
    const agent = await prisma.agent.findFirst({
      where: { id: agentId, orgId },
      select: { id: true },
    });
    if (!agent) return NextResponse.json({ error: "Agent not found" }, { status: 404 });
  }

  const pref = await prisma.alertPref.findFirst({ where: { orgId, agentId } });
  if (!pref) return NextResponse.json({ mode: "immediate", severityFloor: "warning" });
  return NextResponse.json({ mode: pref.mode, severityFloor: pref.severityFloor });
}

export async function PUT(req: NextRequest) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const { orgId } = await getOrCreateOrg(user);

  let body: unknown;
  try { body = await req.json(); } catch { return NextResponse.json({ error: "Invalid JSON" }, { status: 400 }); }

  const parsed = AlertPrefUpdateSchema.safeParse(body);
  if (!parsed.success) return NextResponse.json({ error: "Invalid payload" }, { status: 400 });

  const { mode, severityFloor, agentId, slackWebhookUrl, customEvalCriteria } = parsed.data;
  const resolvedAgentId = agentId ?? null;
  const resolvedSlack = slackWebhookUrl || null;

  if (resolvedAgentId) {
    const agent = await prisma.agent.findFirst({ where: { id: resolvedAgentId, orgId }, select: { id: true } });
    if (!agent) return NextResponse.json({ error: "Agent not found" }, { status: 404 });
  }

  const existing = await prisma.alertPref.findFirst({ where: { orgId, agentId: resolvedAgentId }, select: { id: true } });
  if (existing) {
    await prisma.alertPref.update({ where: { id: existing.id }, data: { mode, severityFloor, slackWebhookUrl: resolvedSlack, customEvalCriteria: customEvalCriteria ?? null } });
  } else {
    await prisma.alertPref.create({ data: { orgId, agentId: resolvedAgentId, mode, severityFloor, slackWebhookUrl: resolvedSlack, customEvalCriteria: customEvalCriteria ?? null } });
  }

  await prisma.auditLog.create({
    data: {
      orgId,
      userId: user.id,
      action: "alert_pref.updated",
      details: { mode, severityFloor },
    },
  });

  return NextResponse.json({ ok: true });
}

import { NextRequest, NextResponse } from "next/server";
import { createHash } from "node:crypto";
import { prisma } from "@atlas/db";
import { verify, ToolCallSchema } from "@atlas/shared";
import { z } from "zod";

const MAX_BODY_BYTES = 262_144;

const RedactedIngestSchema = z.object({
  projectToken: [REDACTED]
  agentId: z.string().min(1).max(256),
  externalTraceId: z.string().min(1).max(256),
  timestamp: z.string().datetime(),
  redactedPrompt: z.string().max(50_000),
  redactedResponse: z.string().max(50_000),
  toolCalls: z.array(ToolCallSchema).optional().default([]),
  tokenCount: z.number().int().nonnegative().optional(),
  costCents: z.number().nonnegative().optional(),
  platform: z.string().max(64).optional(),
  rawRedactedPayload: z.record(z.unknown()),
});

export async function POST(req: NextRequest) {
  const workerSecret = process.env.INGEST_WORKER_SECRET;
  if (!workerSecret) {
    return NextResponse.json({ error: "Server misconfigured" }, { status: 500 });
  }

  const contentLength = req.headers.get("Content-Length");
  if (contentLength && parseInt(contentLength, 10) > MAX_BODY_BYTES) {
    return NextResponse.json({ error: "Payload too large" }, { status: 413 });
  }

  const rawBody = await req.text();
  if (rawBody.length > MAX_BODY_BYTES) {
    return NextResponse.json({ error: "Payload too large" }, { status: 413 });
  }

  const signature = req.headers.get("X-Atlas-Signature") ?? "";

  const valid = await verify(rawBody, signature, workerSecret);
  if (!valid) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: unknown;
  try {
    body = JSON.parse(rawBody);
  } catch {
    return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
  }

  const parsed = RedactedIngestSchema.safeParse(body);
  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
  }

  const data = parsed.data;

  try {
    const tokenHash = createHash("sha256").update(data.projectToken).digest("hex");

    const connection = await prisma.connection.findUnique({
      where: { projectTokenHash: tokenHash },
      include: { org: true },
    });

    if (!connection || connection.status !== "active") {
      return NextResponse.json({ error: "Invalid project token" }, { status: 403 });
    }

    const orgId = connection.orgId;

    const agent = await prisma.agent.upsert({
      where: { orgId_externalId: { orgId, externalId: data.agentId } },
      update: { lastSeenAt: new Date() },
      create: {
        orgId,
        externalId: data.agentId,
        displayName: data.agentId,
        lastSeenAt: new Date(),
        ...(data.platform ? { platform: data.platform } : {}),
      },
    });

    const existing = await prisma.trace.findFirst({
      where: { agentId: agent.id, externalTraceId: data.externalTraceId },
      select: { id: true },
    });

    if (!existing) {
      await prisma.trace.create({
        data: {
          org: { connect: { id: orgId } },
          agent: { connect: { id: agent.id } },
          externalTraceId: data.externalTraceId,
          timestamp: new Date(data.timestamp),
          redactedPrompt: data.redactedPrompt,
          redactedResponse: data.redactedResponse,
          toolCalls: data.toolCalls as unknown as object,
          rawRedactedPayload: data.rawRedactedPayload as unknown as object,
          status: "received",
          ...(data.tokenCount !== undefined ? { tokenCount: data.tokenCount } : {}),
        },
      });
    }
  } catch {
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }

  return NextResponse.json({ ok: true }, { status: 201 });
}

import { createClient } from "@/lib/supabase/server";
import { getOrCreateOrg } from "@/lib/get-auth-org";
import { redirect } from "next/navigation";
import { appUrl } from "@/lib/app-path";
