}

interface GenerateResult {
  text: string;
  usage?: {
    promptTokens?: number;
    completionTokens?: number;
    totalTokens?: number;
  };
  toolCalls?: Array<{
    toolName: string;
    args: unknown;
    result?: unknown;
  }>;
}

export async function wrapVercelAI<T extends GenerateResult>(
  client: AtlasSynapseClient,
  fn: () => Promise<T>,
  options: VercelAIWrapOptions,
): Promise<T> {
  const result = await fn();

  const toolCalls = (result.toolCalls ?? []).map((tc) => ({
    name: tc.toolName,
    input: typeof tc.args === "object" && tc.args !== null
      ? (tc.args as Record<string, unknown>)
      : { args: tc.args },
    output: tc.result,
  }));

  const tokenCount =
    (result.usage?.totalTokens ??
    ((result.usage?.promptTokens ?? 0) + (result.usage?.completionTokens ?? 0))) || null;

  await client.trace({
    prompt: options.prompt,
    response: result.text,
    tokenCount,
    toolCalls,
    ...(options.agentName !== undefined ? { agentName: options.agentName } : {}),
    platform: "vercel-ai",
  });

  return result;
}

interface StreamFinishEvent {
  text: string;
  usage?: {
    promptTokens?: number;
    completionTokens?: number;
    totalTokens?: number;
  };
  toolCalls?: Array<{
    toolName: string;
    args: unknown;
    result?: unknown;
  }>;
}

export function vercelOnFinish(
  client: AtlasSynapseClient,
  options: VercelAIWrapOptions,
): (event: StreamFinishEvent) => void {
  return (event: StreamFinishEvent): void => {
    const toolCalls = (event.toolCalls ?? []).map((tc) => ({
      name: tc.toolName,
      input: typeof tc.args === "object" && tc.args !== null
        ? (tc.args as Record<string, unknown>)
        : { args: tc.args },
      output: tc.result,
    }));

    const tokenCount =
      (event.usage?.totalTokens ??
      ((event.usage?.promptTokens ?? 0) + (event.usage?.completionTokens ?? 0))) || null;

    client
      .trace({
        prompt: options.prompt,
        response: event.text,
        tokenCount,
        toolCalls,
        ...(options.agentName !== undefined ? { agentName: options.agentName } : {}),
        platform: "vercel-ai",
      })
      .catch((err: unknown) => {
        const msg = err instanceof Error ? err.message : String(err);
        console.warn(`[AtlasSynapse] streamText onFinish trace failed: ${msg}`);
      });
  };
}

